1720 
1721     // Compute X & (C2 << Y).
1722     Value *NewAnd = Builder.CreateAnd(Shift->getOperand(0), NewShift);
1723     return replaceOperand(Cmp, 0, NewAnd);
1724   }
1725 
1726   return nullptr;
